import{_ as t,o,c as r,aj as i,j as a}from"./chunks/framework.CYOtwdq0.js";const p=JSON.parse('{"title":"Why coding feels magical","description":"","frontmatter":{},"headers":[],"relativePath":"br/articles/why-coding-feels-magical.md","filePath":"br/articles/why-coding-feels-magical.md"}'),n={name:"br/articles/why-coding-feels-magical.md"};function s(l,e,c,d,h,g){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="why-coding-feels-magical" tabindex="-1">Why coding feels magical <a class="header-anchor" href="#why-coding-feels-magical" aria-label="Permalink to “Why coding feels magical”">​</a></h1><p><em>special thanks to Grammarly</em></p><p>Books are funny.</p><p>They&#39;re a collection of words written in a way that can entertain you, make you laugh, and even cry. When reading Harry Potter, you will get yourself into a world inside your own head where everything feels adventurous and mystical.</p><p>For me, coding goes beyond just being both the writer and the reader. Coding is like playing Dungeons &amp; Dragons, where you create an adventure by designing rules, challenges, and outcomes, shaping a world through your imagination—only here, that world comes alive in code.</p><p>Constructing a logic where a user sends product data that needs to be validated by the front end, then the back end, and then stored in the database feels like an adventure in my head.</p><p>It feels <strong>magical</strong> to take out the logic inside your head and type it out in english in the form of computer instructions using a keyboard just to see your machine do what you asked it to do.</p><p>As Gabe Newell once said,</p><p>&quot;The programmers of tomorrow are the wizards of the future.&quot;</p>',9),a("iframe",{class:"w-full aspect-video",src:"https://www.youtube.com/embed/Dv7gLpW91DM?start=292",title:"Why Programming Is Important?",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture",referrerpolicy:"strict-origin-when-cross-origin",allowfullscreen:""},null,-1),a("p",null,"I like to think that I'm a wizard creating a magic spell, but instead of unintelligible ancient words, it's just JavaScript.",-1)])])}const m=t(n,[["render",s]]);export{p as __pageData,m as default};
